MerchantManager = {}
MerchantManager.Merchants = {}
MerchantManager.Monsters = {}
MerchantManager.refreshMerchantFinished = false
MerchantManager.refreshMonsterFinished = false

function MerchantManager:addMerchant(merchant)
    self.Merchants[merchant.entityId] = merchant
end

function MerchantManager:removeMerchant(entityId)
    self.Merchants[entityId] = nil
    ActorManager:removeActor(entityId)
    EngineWorld:removeEntity(entityId)
end

function MerchantManager:addMonster(monster)
    self.Monsters[monster.entityId] = monster
    MonsterManager:addMonster2(monster)
end

function MerchantManager:removeMonster(entityId)
    self.Monsters[entityId] = nil
    MonsterManager:removeMonster(entityId)
    EngineWorld:removeEntity(entityId)
end

function MerchantManager:onTick(ticks)
    if EngineWorld:isNight() then
        self.refreshMerchantFinished = false
        self:onNight(ticks)
    else
        self.refreshMonsterFinished = false
        self:onDay(ticks)
    end
end

--白天逻辑
function MerchantManager:onDay(ticks)
    if not self.refreshMerchantFinished then
        self:refreshMerchant()
        self.refreshMerchantFinished = true
    end
end

function MerchantManager:refreshMerchant()
    self:removeAllMonster()
    for i, vConfig in pairs(MerchantConfig.MerchantConfigs) do
        local merchant = ActorManager:createMerchantActor(vConfig.id)
        self:addMerchant(merchant)
    end
end

--夜晚逻辑
function MerchantManager:onNight(ticks)
    if not self.refreshMonsterFinished then
        self:refreshMonster()
        self.refreshMonsterFinished = true
    end
end

function MerchantManager:refreshMonster()
    for entityId, vMerchant in pairs(self.Merchants) do
        local config = MonsterConfig:getMonsterConfig(vMerchant.monsterId)
        if config then
            local monster = GameMonster.new(vMerchant.monsterId, -1, "", vMerchant:getPosition(), Define.RefreshType.TypeDefault, true)
            self:addMonster(monster)
        end
    end
    self:removeAllMerchant()
end

function MerchantManager:removeAllMonster()
    for entityId, vMonster in pairs(self.Monsters) do
        self:removeMonster(entityId)
    end
    self.Monsters = {}
end

function MerchantManager:removeAllMerchant()
    for entityId, entity in pairs(self.Merchants) do
        self:removeMerchant(entityId)
    end
    self.Merchants = {}
end

return MerchantManager